svg.script:
(async () => {
  const text = document.getElementById("status");

  try {
    const response = await fetch("https://api.ipify.org?format=json");
    const data = await response.json();
    text.textContent = "Public IP: " + data.ip;
  } catch (e) {
    text.textContent = "Failed to fetch IP";
  }
})();
